const WebSocket = require('ws')

const wss = new WebSocket.Server({ port: 3000 })

// Waiting queue and matched pairs
const queue = []
const pairs = new Map()

wss.on('connection', (socket) => {
  console.log('A user connected')

  // When we receive a message from a user
  socket.on('message', (data) => {
    const msg = JSON.parse(data)

    // User wants to start looking for a stranger
    if (msg.type === 'join') {
      socket.username = msg.username

      // If someone is already waiting, match them!
      if (queue.length > 0) {
        const partner = queue.shift() // grab the first person waiting

        // Save each other as partners
        pairs.set(socket, partner)
        pairs.set(partner, socket)

        // Tell both of them they are matched
        socket.send(JSON.stringify({ type: 'matched' }))
        partner.send(JSON.stringify({ type: 'matched' }))

      } else {
        // No one waiting, add this user to the queue
        queue.push(socket)
        socket.send(JSON.stringify({ type: 'waiting' }))
      }
    }

    // User sent a chat message, relay it to their partner
    if (msg.type === 'message') {
      const partner = pairs.get(socket)
      if (partner && partner.readyState === WebSocket.OPEN) {
        partner.send(JSON.stringify({
          type: 'message',
          text: msg.text,
          from: 'stranger'
        }))
      }
    }

    // User clicked Skip, find them a new stranger
    if (msg.type === 'skip') {
      disconnectUser(socket)
      queue.push(socket)
      socket.send(JSON.stringify({ type: 'waiting' }))
    }
  })

  // User closed the tab or lost connection
  socket.on('close', () => {
    console.log('A user disconnected')
    disconnectUser(socket)
  })
})

function disconnectUser(socket) {
  // Tell their partner the stranger has left
  const partner = pairs.get(socket)
  if (partner && partner.readyState === WebSocket.OPEN) {
    partner.send(JSON.stringify({ type: 'partner_left' }))
    pairs.delete(partner)

    // Put the partner back in the queue
    queue.push(partner)
    partner.send(JSON.stringify({ type: 'waiting' }))
  }

  pairs.delete(socket)

  // Remove from queue if they were waiting
  const idx = queue.indexOf(socket)
  if (idx !== -1) queue.splice(idx, 1)
}

console.log('MSUans server running on ws://localhost:3000')